var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"......박물관장은 어쩔 줄 몰라 했고, 관람객들은 내게 박수갈채를 보냈지.","JPN":"……博物館の館長は戸惑い気味だったけど、\\n来館客はボクに拍手喝采を送ってくれた。","ENG":"... The museum director didn't know what to do while the audience gave me a standing ovation.","TWN":"……博物館館長不知所措，而觀眾向我鼓掌喝彩。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그렇게 해서 난 사람들의 호응을 얻어서 청소부 겸 큐레이터 역할을 맡게 된 거야.","JPN":"そうやってボクは人々に認められ、掃除係兼\\n学芸員の役割を担うことになったんだ。","ENG":"That's how I became a cleaner plus curator, owing to my popularity.","TWN":"我得到了人們的支持，開始了清掃工兼經紀人的工作。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"하아, 파란만장하고도 뜻 깊은 시절이었지.","JPN":"はあ、実に波乱万丈で充実した日々だったよ。","ENG":"Ah, that was such an eventful and meaningful time of my life!","TWN":"哎，是一段波瀾萬丈又很有意義的時期。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......스캔 완료. 카테고리 분류...... 문화 잡지.","JPN":"……スキャン完了。カテゴリー仕分け……文化系雑誌。","ENG":"... Scanning completed. Category: Cultural magazine.","TWN":"……掃描完畢，分類為……文化雜誌。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L7_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"이곳에 와서 한 달이 넘도록 종이쪼가리나 찾아 다니는 너와는 다르게 말이야.","JPN":"ここに来てから一か月以上も紙切れなんか探している\\nキミとは違ってね。","ENG":"I never wasted my time like you're doing right now, looking at random pieces of paper pretty much non-stop for like a month.","TWN":"我可跟你不一樣，一個多月以來只知道收集一些破紙片。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_02"},{"id":"L14_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그래, 그래. 대강의 사정은 알겠어. 이 도시에서 쓸만한 정보들을 수집하려는 거지?","JPN":"わかるよわかる、だいたいの事情はね。この街で\\n有用な情報を収集したいんだろ？","ENG":"Yeah, yeah, I get it. You're trying to collect useful information in this city, right?","TWN":"知道，我知道。我知道你的意圖。你是想在這個城市收集有用的資訊是吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"물론 삶에 목표를 갖는 게 중요하다는 건 동의해.","JPN":"もちろん、人生の目標を持つのは大事さ。","ENG":"I agree that having a purpose is important.","TWN":"我也認為人生確實需要有一個目標。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"나도 낙엽이 쌓인 거리를 청소해서 사람들을 기쁘게 하는 것이 삶의 낙이었던 시절이 있었거든.","JPN":"ボクも街中の落ち葉を掃除して人々を喜ばせるのが\\n生きがいだったことがあったからね。","ENG":"I used to clean leaves off the street to make people happy.","TWN":"打掃大街上的落葉，使人們開心曾經是我人生的一大快樂。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"하지만 말이야.","JPN":"でもね。","ENG":"But you know what?","TWN":"但是，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"내가 아무리 멍청한 청소용 로봇이라 해도 빗자루 하나로 이 무너진 도시를 혼자 깨끗하게 만들 수 없다는 것쯤은 안다고.","JPN":"ボクがどんなにおバカなロボットでも、ボクひとりで、箒一つで、\\n破壊されてしまったこの街をきれいにすることは\\nできないってことくらい、わかるんだ。","ENG":"I may be a stupid cleaning robot, but at least I know that I can't clean this whole city and put it back together by myself.","TWN":"就算我是一個傻乎乎的清掃機器人，我也知道我不可能僅憑一把掃帚就能清理乾淨這個破舊的城市。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"이 세상엔 더 이상 쓸만한 지식도 없고, 그 지식을 필요로 하는 사람도 없어.","JPN":"この世界にはこれ以上役に立つ知識もなければ、\\nその知識を必要とする人もいない。","ENG":"This world no longer has any useful knowledge left in it, or anyone who needs such knowledge for that matter.","TWN":"這個世界上沒有什麼有用的知識，也沒有需要用到那些知識的人類。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"그러니까 그런 비생산적인 일은 그만둬.","JPN":"だから、そんな無駄なことを続けるのはやめなよ。","ENG":"So, stop being so unproductive.","TWN":"所以別再做這些沒意義的事情了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"명령 같은 건 무시하고, 네가 하고 싶은 걸 찾으라는 거야.","JPN":"命令なんか無視して、キミのやりたいことを探せってこと。","ENG":"Ignore your orders and find something else you want to do.","TWN":"別管那些命令，做你想做的事情吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NONAME_MECH","text":{"KOREA":"......스캔 완료. 카테고리 분류...... 지역 신문.","JPN":"…………スキャン完了。カテゴリー仕分け……\\nローカル新聞。","ENG":"... Scanning completed. Category: Local newspaper.","TWN":"……掃描完畢，分類為……地區新聞。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L23_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"하아...... 됐다. 내 말은 잊어버려. 하던 일이나 하라고.","JPN":"はあ……もういいや、ボクの話は忘れて。キミの\\n仕事に集中すればいい。","ENG":"*Sigh* Forget it. Just forget what I said and keep doing what you're doing.","TWN":"唉……算了，不要在意我說的話。繼續你的工作吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"또 왔군. 괜히 휘말리기 전에 지하로 내려가야겠어.","JPN":"また来たな。巻き込まれる前に地下に移動しようっと。","ENG":"Here they come again. We'd better get underground before they see us.","TWN":"又來了，得在被發現之前到地下去。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"아, 이런. 이젠 지하도 너희들이 가지시겠다?","JPN":"しまった。これからは地下もキミたちが占領するのかい？","ENG":"Oh, great. You want the basement, too?","TWN":"啊，你們想霸佔地下嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"좋아. 여긴 너희들이 가지라고. 난 옆 건물로......","JPN":"まあいいか、ここはキミたちにあげるよ。\\nボクはとなりの建物に……","ENG":"Sure, keep it all to yourselves. I can always move to the next building—","TWN":"好，這個地方歸你們，我要去旁邊的大樓……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_TANK_MOVE"},{"id":"L33_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"좋아, 내 추측대로라면 아무래도 우린 포위된 거 같아.","JPN":"ボクの勘が間違ってなければ、どうやら\\n囲まれているみたいだ。","ENG":"Alright, this is what I think: we're surrounded.","TWN":"好，據我推測，我們好像被包圍了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"이제 어쩌지?","JPN":"どうしようか？","ENG":"What do we do now?","TWN":"現在怎麼辦？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NONAME_MECH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};